LOCK TABLES `libreria_productotemporada` WRITE;
/*!40000 ALTER TABLE `libreria_productotemporada` DISABLE KEYS */;
INSERT INTO `libreria_productotemporada` VALUES (1,'Palta','Otoño-Invierno-Primavera','Fruta de textura suave y cremosa, de sabor mantecoso y agradable. Es un alimento nutritivo rico en antioxidantes, ácidos grasos, flavonoides, aceite oleico y linoleico.','productos/palta_pcKGDpr.png'),(2,'Acelga','Otoño-Invierno-Primavera','Hortaliza de hojas grandes, carnosas y ovalada., De color varia entre verde oscuro y verde claro con nervios marcados, entre los cuales destaca mas su nervio central que es suave y crujiente. Sus tallos o pencas pueden ser de color blanco o rojo.\r\nRico en nutrientes y bajo nivel calórico. fuente de minerales y vitaminas, de las cuales destacan yodo, hierro, magnesio y potasio, entre otros. Muy rico en fibra soluble, favorable al transito intestinal.','productos/acelga_5VmsBw3.jpg'),(3,'Pomelo','Otoño-Invierno','Fruta cítrica de forma de globo, cubierta de una cascara gruesa y carnosa. De pulpa jugosa y puede ser color amarillo, rosado o rojo.\r\nRico en agua y vitamina C, también contiene vitaminas A, B1, B2 y B9 o ácido fólico. Contiene minerales como selenio, hierro, magnesio, azufre, fósforo o potasio, carotenoides antioxidantes, acido málico, entre otros.','productos/pomelo_8FCsz53.png'),(4,'Batata','Otoño-Invierno','Raíz tuberosa comestible similar en textura a la papa, pero con un sabor dulce y salado a la vez. Son ricas en antioxidantes y fibra, potasio, calcio, manganeso y betacarotenos, especialmente las variedades amarillas o anaranjadas. Fuente de vitaminas A, C y niacina. También se caracterizan por ser un alimento de bajo índice glucémico.','productos/batata-morada_0fxYWZZ.jpg'),(5,'Apio','Otoño-Invierno','Hortaliza de color verde, con tallos que forman una penca y hojas similares al cilantro. Es una planta herbácea que crece hasta 90 cm de altura. De textura crujiente y fresca, sabor fuerte y aromático. Es rico en agua, fibra, potasio, vitaminas A, B, C y K, y ácido fólico. De propiedades diuréticas y depurativas, también antioxidantes y es un sedante natural, ideal para los nervios.','productos/apio_IKRWCVO.jpeg'),(6,'Zanahoria','Otoño-Invierno','Raíz vegetal de color naranja, de la familia de las umbelíferas. Es un tubérculo hipocalórico, de textura leñosa y firme, puede ser cilíndrica o redonda. Es rica en vitaminas y minerales. Tiene propiedades diuréticas. Es buena para eliminar los cólicos y favorece la digestión','productos/zanahoria_wWprvEj.jfif'),(7,'Limón','Otoño-Invierno-Primavera-Verano','El limón es una fruta cítrica, pequeña y amarilla como su variedad mas conocida, rica en vitamina C y ácido cítrico. Es un alimento muy versátil que se usa en la cocina, la medicina y la cosmética. Su pulpa del limón es de color amarillo pálido y está dividida en segmentos. Es rico en potasio y otros nutrientes. Tiene propiedades antioxidantes y antiinflamatorias, útiles para ayudar a la digestión y a disolver los cálculos renales, es bueno para el hígado, reforzar el sistema inmunológico y prevenir enfermedades, sobre todo las respiratorias.','productos/limon_ld27gyQ.jpg'),(8,'Repollo','Otoño-Invierno','Es una verdura crucífera que se caracteriza por ser una planta compacta y de hoja resistente. Puede ser esférico, achatado o alargado .Sus hojas pueden ser lisas o crespas. Su color puede variar de verde a rojo oscuro. Sus cabezas pueden ser pequeñas y muy firmes.  Es rico en vitaminas, minerales, antioxidantes y agua. Destacan potasio, calcio y magnesio, compuestos de azufre como principal antioxidante, las vitaminas A y C. También es rico en fibras, bajo en sodio y grasas.','productos/repollo-redondo-cv_1200_FrV7sHV.jpg'),(9,'Zapallo','Otoño-Invierno-Verano','Es una fruta tropical alargada, carnosa y con una cáscara gruesa, que proviene del árbol del banano. Es rica en potasio, vitaminas y minerales. Destacan potasio, magnesio, selenio, calcio y hierro, acido fólico y vitaminas A, B, C y E. Es rica en triptófano, un aminoácido esencial que ayuda a la saciedad.','productos/zapallo-verde_2XLF8r2.jpeg'),(10,'Pera','Otoño-Invierno-Verano','La pera es una fruta jugosa, refrescante y nutritiva. Es el fruto del peral, un árbol de la familia de las rosáceas. Su forma es similar a una bombilla, su cáscara es lisa y puede ser verde, amarilla, café o rojiza. Su pulpa es blanca, verdosa, compacta y jugosa. Es rica en vitaminas A, B, C y K. Contiene minerales como cobre, hierro, potasio y magnesio. Es una excelente fuente de fibra.\r\nTiene un bajo índice glucémico.\r\nContiene pectina, que es beneficiosa para el sistema digestivo.','productos/pera_ndQfjHh.jpg'),(11,'Mandarina','Otoño-Invierno','La mandarina es una fruta cítrica de forma esférica, color anaranjado, similar a la naranja, pero más pequeña y achatada. Es muy apreciada por su sabor dulce y facilidad para pelarla. Rica en vitamina C, flavonoides, betacaroteno, y aceites esenciales. Tiene como principales propiedades fortalecer el sistema inmunológico, previene enfermedades cardiovasculares, y ayuda a disminuir el colesterol.','productos/mandarina_gkRPEH4.jpg'),(12,'Remolacha','Otoño-Invierno-Primavera','La remolacha es una hortaliza con raíz carnosa, globosa y de color rojo oscuro. Su color varía de rosáceo a violáceo y anaranjado rojizo hasta el marrón. \r\nSu pulpa suele ser de color rojo oscuro y puede presentar en ocasiones círculos concéntricos de color blanco. Es rica en nutrientes, como hierro, ácido fólico y vitamina C. Contiene nitratos, que se convierten en óxido nítrico en el cuerpo y pueden mejorar la salud cardiovascular. \r\nEs baja en grasa, en colesterol y en calorías.','productos/remolacha_Hlq8nUF.jpg'),(13,'Naranja','Otoño-Invierno-Primavera-Verano','La naranja es una fruta cítrica con una cáscara exterior que puede ser de color verde, amarillo brillante o naranja intenso, pulpa jugosa y gajos carnosos. Su sabor puede ser dulce o ligeramente agrio, dependiendo de la variedad. Es rica en vitamina C, vitamina A, folatos, fibra y potasio. Es buena para el estreñimiento y ayuda a combatir la anemia, por nombrar alguno de sus beneficios.','productos/naranja_UuIgLhs.jpg'),(14,'Ciruela','Otoño-Invierno','Las ciruelas son frutos del ciruelo, un árbol del subgénero Prunus, y son consideradas una drupa, es decir, un fruto carnoso con una única semilla. Existen diversas variedades de ciruelas, como las europeas (azules y púrpuras, a menudo usadas para ciruelas pasas) y las japonesas (rojas y amarillas, jugosas y dulces). \r\nContienen vitaminas (A y C), potasio y antioxidantes, que contribuyen a una buena salud general. Son ricas en fibra, lo que ayuda a mejorar el tránsito intestinal y a prevenir el estreñimiento.','productos/ciruela_Ck56yY5.jpg'),(15,'Durazno','Otoño-Invierno-Verano','El durazno es una fruta globosa, aterciopelada y de color amarillo, con tonalidades rojizas. Mide entre 5 y 7.5 cm de diámetro, tiene una única semilla, su pulpa madura es firme, dulce y jugosa. Su hueso es muy duro y también tiene hendiduras. \r\nEs una excelente fuente de antioxidantes como las vitaminas A y C, Contiene potasio, esencial para la función muscular y cardiovascular. Es una opción ideal para cuidar el peso corporal y mantenerse hidratado gracias a su bajo contenido calórico y alto porcentaje de agua.','productos/durazno_dvzZRjh.jpg'),(16,'Cebolla de Verdeo','Otoño-Invierno','La cebolla de verdeo es una planta herbácea de la familia de las aliáceas que se utiliza por sus hojas.  Tiene sabor y aroma similar a la cebolla, pero esta es mas tierna y tiene un sabor mas dulce. Es una excelente fuente de vitamina K, tiene propiedades diuréticas y antiespasmódicas. Ayuda a prevenir cuadros gripales y resfríos.','productos/cebolla-de-verdeo_H5ftj5c.jpg'),(17,'Puerro','Otoño-Invierno-Primavera','El puerro es una verdura de la familia de las cebollas, ajos y cebolletas, que se caracteriza por sus  hojas alargadas de color verde a verde-azulado oscuro y su sabor suave. Esta compuesto por un sistema radicular con muchas raíces que pueden alcanzar hasta 50 cm de profundidad.\r\nRico en vitamina C, calcio, potasio, fósforo, ácido fólico y hierro.\r\nBajo en sodio, libre de grasa, diurético y laxante natural. Como propiedades destacadas resaltan ser muy buen antiinflamatorio y anticancerígeno.','productos/Puerro_RNWjMhP.jpg'),(18,'Melón','Otoño-Invierno-Verano','El melón es una fruta dulce y refrescante de la planta herbácea Cucumis melo. Es una cucurbitácea, como la sandía, el pepino y la calabacita. Su epidermis puede ser blanca, gris, verdosa o amarilla y de textura lisa, rugosa o reticulada. \r\nSu pulpa es aromática, con textura suave y diferentes colores: amarillo, verde, rosado y tonos intermedios. \r\nEs rica en vitamina C y A, esta ultima hace que sea un eficaz aliado contra el cáncer y padecimientos cardíacos. Aporta también muchos carbohidratos, como sacarosa, pero por su bajo contenido en energía resulta ideal para perder peso. Calcio, magnesio, potasio y fósforo son otras de sus virtudes para el organismo.','productos/Melon_A3s2MbH.jpg'),(19,'Brócoli','Otoño-Invierno','El brócoli es una verdura de la familia de las crucíferas, con muchas cabezas florales carnosas de color verde, con vetas blancas. Su textura es compacta y tierna, sin partes fibrosas.\r\nPosee nutrientes destacados como la vitamina C, potasio, calcio, hierro, ácido fólico, fibra y antioxidantes.\r\nDestacan propiedades anticancerígenas, protección ósea y desintoxicación del organismo.','productos/brocoli-ramas_KvdH6Yv.jpg'),(20,'Coliflor','Otoño-Invierno','La coliflor es una verdura de la familia de las Crucíferas con forma redondeada y carnosa. Su cabeza es blanca y está formada por ramilletes pequeños y apretados.\r\nEs una fuente importante de vitamina C, B6, K y b9. También contiene una gran cantidad de aportes minerales, especialmente potasio, magnesio o fósforo. Posee propiedades digestivas (rica en fibras), antioxidantes, antiinflamatorias, inmunológicas y óseas.','productos/coliflor_fMKjKac.jpg'),(21,'Hinojo','Otoño-Invierno','El hinojo es una planta herbácea con un aroma anisado que se usa en la cocina, la medicina y la cosmética. Posee tallos huecos, hojas ramificadas, lineales y de color verde intenso. Puede llegar a medir 2 metros de altura.\r\nContiene vitaminas B (B3, B6 y B9 o ácido fólico), provitamina A, vitamina C y minerales (potasio, fósforo, hierro, calcio y magnesio).\r\nPosee diversas propiedades beneficiosas para la salud, incluyendo la mejora de la digestión, la eliminación de gases, la reducción de la retención de líquidos y propiedades antiinflamatorias y antioxidantes.','productos/hinojo_uRV5KOF.jpg'),(22,'Membrillo','Otoño-Invierno','El membrillo es una fruta de forma periforme, color amarillo-dorado, con una pulpa dura y aromática, conocida por consumirse principalmente cocida en postres. Cuando está inmaduro, es verde y cubierto de pelos grisáceos. Es astringente cuando está crudo.\r\nEs rico en nutrientes como las vitaminas A, B y C y bajo en grasas.\r\nEs diurético, contiene fibra, que ayuda al aparato digestivo\r\nContiene potasio, que mejora los niveles de colesterol.','productos/membrillo_ikq0tQN.jpg'),(23,'Frutilla','Primavera','Las frutillas son frutos carnosos, rojos, dulces y con forma de corazón. Tienen un intenso aroma y su sabor varía de ácido a muy dulce. Son bajas en calorías y son ricas en antioxidantes, vitamina C, fibra, potasio, ácido fólico y minerales. \r\nAyudan a mantener la piel hidratada, Combaten el estreñimiento, Evitan enfermedades oculares, Reducen problemas cardiovasculares, Son recomendables en dietas cuyo objetivo sea controlar o bajar el peso.','productos/frutilla_i41TWKh.jpg'),(24,'Manzana','Primavera-Verano','La manzana es una fruta carnosa, jugosa y con una piel fina y comestible. Su color, tamaño y sabor varían según la variedad. \r\nSu piel puede ser roja, verde, amarillo, rosa u oxidado. Su sabor va desde dulce a agrio, dependiendo de la variedad. Es rica en fibra, vitamina C, potasio, fósforo, calcio y antioxidantes.\r\nAyuda a moderar los niveles de azúcar en sangre, combate el estreñimiento, mantiene una flora bacteriana saludable como algunas de sus propiedades mas destacadas.','productos/manzanas_rvmXuOx.jpg'),(25,'Arandano','Primavera-Verano','Los arándanos son bayas negruzcas o azuladas, dulces y comestibles que provienen de un arbusto perenne.\r\nLos arándanos son uno de los alimentos con mayor contenido de antioxidantes.\r\nSon ricos antioxidantes, vitaminas, fibra y potasio.\r\nFortalecen el sistema inmunitario y combaten las infecciones, previenen las infecciones urinarias y combaten las bacterias en el aparato digestivo, protegen contra el envejecimiento y enfermedades como el cáncer como algunas de sus propiedades mas destacadas','productos/arandanos_Z2rjz37.jpg'),(26,'Esparrago','Primavera-Verano','El espárrago es una verdura perenne de sabor característico y nutritiva. Es originario del Mediterráneo y se cultiva en todo el mundo. Es una planta arbustiva que puede alcanzar hasta 2 m de altura. Tiene un rizoma grueso y carnoso.\r\nPueden ser verdes o blancos, dependiendo de cómo se cultiven.\r\nSon ricos en vitaminas C y E, fibra y antioxidantes. Tienen un efecto diurético y laxante. Tienen un gran poder antioxidante y son ricos en ácido fólico. Son recomendables para personas que están a dieta.','productos/esparrago_esepcwH.jpeg'),(27,'Lechuga','Primavera','La lechuga es una planta herbácea de la familia de las asteráceas con hojas verdes y crujientes. En argentina hay diferentes variedades, cómo la repollada, que es mas crujiente, y otras no tanto como la mantecosa y la criolla. Es un alimento bajo en calorías y rico en agua, fibra, vitaminas y minerales. \r\nEstimula el buen funcionamiento de los riñones y previene infecciones del tracto urinario. También favorece la absorción de hierro de los alimentos y previene las infecciones.','productos/lechuga_3jxftOy.jpg'),(28,'Zapallito tronco','Primavera','El zapallito de tronco es una planta compacta y de ciclo corto que produce frutos, Redondos, de color verde y de alrededor de 7 cm de diámetro, se pueden consumir frescos, en su estado inmaduro\r\nSus flores también son comestibles. Es rico en vitaminas A, C, E y del complejo B\r\nContiene minerales como potasio, sodio, hierro, calcio, fósforo, ácido fólico, y fibra\r\nFavorece la pérdida de peso, ayuda a prevenir el estreñimiento y enfermedades intestinales.\r\nEs diurético, por lo que es clave para las personas con hipertensión, cálculos renales y retención de líquidos y fortalece el sistema inmunológico como algunas de sus propiedades más destacadas.','productos/zapallito_OQpkSze.jpeg'),(29,'Cereza','Primavera-Verano','La cereza es una fruta redonda y carnosa que proviene del cerezo, un árbol de la familia de las rosáceas.\r\nSu color va desde el rojo claro hasta el morado oscuro.\r\nEs rica en potasio, calcio, magnesio, hidratos de carbono, y vitaminas A, B9 y C y antioxidantes como las antocianinas y el ácido elágico.\r\nEntre sus propiedades y beneficios destaca la ayuda a mantener el buen estado de salud del organismo.\r\nContiene fibra, lo que le confiere un carácter laxante y \"depurativo\" del organismo.\r\nAyuda al cuidado del cabello.\r\nAyuda al sistema inmunitario y a la salud del corazón.\r\nPuede reducir la inflamación causada por afecciones como la gota.','productos/cereza_aCtnrHf.jpg'),(30,'Banana','Otoño-Invierno-Primavera','La banana es una fruta tropical alargada, carnosa y cubierta de cáscara que proviene del árbol del banano.\r\nSu piel es gruesa y de color amarillo, verde, rojo, púrpura, dorada o marrón \r\nSu pulpa es blanca o amarillenta y de textura blanda y dulce.\r\nContiene vitaminas A, B, C y E y minerales como  potasio, magnesio, selenio, calcio y hierro.\r\nEstas son algunas de sus propiedades: Buenas para el sistema cardiovascular, regula el transito intestinal, promueve la salud digestiva gracias a su contenido de fibras, ayuda a prevenir calambres musculares.','productos/Bananas_m0WEBXE.jpg'),(31,'Perejil','Primavera','El perejil es una planta herbácea aromática con hojas verdes, tallo anguloso y flores blanco verdosas. Las hojas son lustrosas, de color verde oscuro, partidas en tres gajos dentados; pueden ser lisas o rizadas. Tiene un sabor fresco, ligeramente amargo y picante, con un toque terroso. \r\nPosee propiedades antioxidantes, antiinflamatorias, diuréticas, antibacterianas, y es rico en vitaminas A, C, y K y minerales como el potasio, fósforo, calcio, hierro, y azufre.','productos/perejil_plTF09H.jpg'),(32,'Frambuesa','Primavera-Verano','La frambuesa es una fruta pequeña, roja o rosada, con un sabor agridulce. Es el fruto del arbusto Rubus idaeus, conocido como frambueso. Su tamaño es como la yema de un dedo. Su Forma es como un cono o media esfera. De textura blanda, un poco peluda y su interior hueco (como un capuchón).\r\nEs rica en fibra, antioxidantes, vitamina C, potasio, calcio, fósforo y carbohidratos.\r\nBaja en calorías y azúcares.\r\nAyuda a regular los niveles de colesterol, favorece la circulación sanguínea, ayuda a controlar la presión arterial y Alivia los problemas intestinales y previene el estreñimiento, como sus propiedades más destacadas.','productos/frambuesa_lYGWha2.jpg'),(33,'Ananá','Primavera-Verano','El ananá, también conocido como piña, es una fruta tropical ovalada, jugosa y dulce. Su pulpa es de color amarillo y textura carnosa. Su corteza es verde y se torna anaranjada al madurar.\r\nEs rica en vitamina C, fibra, yodo, hierro, magnesio, zinc y manganeso. \r\nEs diurético, antibacteriano, fortalece el sistema inmune y buena para la digestión y el transito intestinal.','productos/ananá_fEUAq6D.jpg'),(34,'Rabanito','Otoño-Invierno-Verano','El rabanito es una hortaliza de raíz carnosa y picante de color rojo. También se puede encontrar en varios colores, desde el blanco hasta el negro.\r\nEs rico en fibra, vitamina C, antioxidantes y compuestos sulfurados. \r\nFortalece el sistema inmunológico.\r\nAyuda a combatir el daño celular.\r\nAyuda a proteger el hígado y aumentar las defensas.\r\nPuede afectar de manera positiva en la absorción y homeostasis de la glucosa y del metabolismo energético general.','productos/rabanito_JKqU9sL.jpg'),(35,'Morrón','Verano','El morrón, también conocido como pimiento morrón, es una hortaliza carnosa, de gran tamaño y forma redonda, cuadrada o también rectangular. Su piel es lisa y brillante, y su sabor es dulce y suave. Sus colores mas característicos son el rojo, el verde y el amarillo.\r\nEs rico en fibra, vitamina C, potasio, y antioxidantes. \r\nMejora el tránsito intestinal, además de poseer un efecto saciante. Ayuda a prevenir el cáncer, las hemorragias cerebrales, las cataratas, y las enfermedades cardíacas. Mejora el sistema inmunológico. Cuida las células y el organismo, retrasando el envejecimiento.','productos/morron_Piw953N.jpg'),(36,'Sandía','Verano','La sandía es una fruta dulce y jugosa que pertenece a la familia de las cucurbitáceas. Su pulpa es de color rojo y contiene muchas pepitas negras y aplastadas.\r\nEs rica en vitamina A, B, C, E y B6 y contiene potasio, magnesio, calcio y fósforo.\r\nAyuda a eliminar toxinas y líquidos retenidos, aliviando el hinchazón y mejorando la digestión. \r\nSu alto contenido en agua ayuda a que la piel esté hidratada y tenga un aspecto más saludable. \r\nContribuyen a mantener una visión óptima y a reducir el riesgo de cataratas. \r\nEs ideal para bajar de peso debido a su bajo contenido de calorías y grasas.','productos/sandias-05_QLEcsNz.jpg'),(37,'Choclo','Verano','El choclo, también conocido como elote, mazorca o maíz tierno, es un vegetal feculento con granos inmaduros. Tiene granos anchos y achatados de color amarillo y sus granos se disponen en hileras lineales desde la base hasta la punta.\r\nEs rico en fibra, vitaminas, minerales y antioxidantes.\r\nComo propiedades destacan ayudar a mejorar la digestión, la salud ocular y el sistema inmunitario.','productos/choclo_7LiBmGR.jpg'),(38,'Cebolla','Verano','La cebolla es una planta herbácea bienal de la familia de las liliáceas. De Forma globosa, esférica o elipsoidal, tiene de diámetro de 3–10 cm, peso de 100–250 g y color blanco, amarillo, rojo intenso, violáceo. De textura firme, compuesta por capas sucesivas y sabor intenso/picante, aunque hay variedades dulces.\r\nEs rica en minerales y oligoelementos, vitaminas A, B, C y E.  Contiene potasio, calcio y magnesio, fundamentales para la salud de los huesos y los dientes. \r\nDestacan también propiedades antiviral, antidiabética, antiinflamatoria, antioxidante, prebiótica.','productos/cebollas_NBakcdQ.jpg'),(39,'Tomate','Verano','El tomate es una fruta de color rojizo, con sabor dulce y ácido. De forma redonda, achatada, o en forma de pera. Su tamaño va desde  cm hasta 16 cm de diámetro, su superficie lisa o asurcada y sus semillas ovales  aplastadas, de color grisáceo o paja, cubiertas de vellosidades.\r\nPosee Vitaminas A, C, K, tiamina, B6 y ácido fólico, además de potasio, fósforo, magnesio, manganeso o cobre. \r\nDe sus propiedades destacan ser antiséptico, alcalinízate, depurativo, diurético, digestivo, laxante, desinflamatorio y remineralizaste.','productos/tomate_9kNNY2O.jpg'),(40,'Pepino','Verano','El pepino es una hortaliza de la familia de las cucurbitáceas, que se caracteriza por ser bajo en calorías y alto en agua. Es una fruta con semillas que crece de la flor de la planta. De forma de baya alargada, cilíndrica y pulposa, color verde cuando está inmaduro, amarillo verdoso y liso cuando está maduro.\r\nSu interior es blanco y contiene numerosas semillas ovaladas de tamaño pequeño. Sus variedades más conocidas son corto o pepinillo, pepino medio largo, pepino largo.\r\nSus principales nutrientes son la fibra, vitaminas A, B, C y E, potasio, hierro, calcio, fósforo y magnesio.\r\nPosee propiedades hidratantes, antioxidantes, diuréticas, depurativas y antiinflamatorias.','productos/pepino_NDEmURt.jfif'),(41,'Berenjena','Verano','La berenjena es una hortaliza de verano de la familia de las solanáceas, que incluye también a los tomates y las papas. Su piel es lisa, brillante y de color morado. Su pulpa es blanca o verde, según la variedad, y tiene semillas blandas. Tiene un sabor suave, vegetal y ligeramente amargo.\r\nEs rica en agua y fibra.\r\nContiene potasio, magnesio, calcio, fósforo, vitamina B6, vitamina B1, ácido fólico.\r\nContiene antocianinas, que tienen propiedades antioxidantes.\r\nEs un alimento ligero y digestivo. Ayuda a controlar el colesterol.\r\nAyuda a controlar el azúcar. Favorece la eliminación de líquidos y reduce la presión arterial.\r\nAyuda a reforzar el sistema nervioso y mejorar el estado de ánimo.','productos/berenjena_46W56Dp.jpg'),(42,'Higo','Verano','El higo es una fruta dulce y carnosa que proviene de la higuera, un árbol de la familia de las moráceas. En realidad, el higo es una infrutescencia, es decir, un conjunto de frutos que se agrupan dentro de la piel.\r\nSu piel es fina y blanda, y puede ser verde, negra o morada. Su pulpa es blanca o encarnada, y está llena de pepitas.\r\nEs rico en vitaminas, calcio, fósforo, hierro, potasio, cloro y sodio.\r\nContiene fibra soluble, que ayuda a controlar los niveles de colesterol y glucosa en la sangre.\r\nAyuda a controlar los niveles de presión arterial alta y se lo recomienda también para mantener en buen estado el sistema nervioso y músculo-esquelético.','productos/higos_27jh1vf.jpg'),(43,'Mora','Verano','La mora es una fruta silvestre de color morado, ovalada y agridulce. Está formada por pequeños glóbulos carnosos y blandos. Es una fruta polidrupa, es decir, está formada por pequeñas drupas dispuestas en racimo.Es baja en calorías y relativamente baja en azúcares naturales. \r\nContiene potasio, magnesio, vitaminas C y K y fibra. \r\nContiene prebióticos, carbohidratos que ayudan a alimentar las bacterias intestinales saludables. \r\nContiene vitaminas A, C y E, lo que aumenta la generación de colágeno y la absorción del hierro. \r\nTiene propiedades antioxidantes, Tiene propiedades antiinflamatorias, Fortalece el sistema inmunológico, Reduce la propagación de bacterias en la boca y fortalece las encías, Es considerada  también un fruto afrodisíaco.','productos/mora2_2acw7Ni.png'),(44,'Uva','Verano','Las uvas son frutos carnosos y jugosos que se agrupan en racimos. Tienen una cáscara delgada y resistente, y su color varía según la variedad.  Son frutos de la parra, una planta trepadora\r\nSu forma puede ser esférica, redonda u ovalada, su color puede ser verdoso, rojizo, púrpura, azulado o amarillento. Su pulpa es jugosa y dulzona, con pequeñas pepitas duras en su interior.\r\nSon ricas en antioxidantes. Contienen fibra en forma de celulosa\r\nSon fuente de vitaminas A, C, E, B1, B2, B3, B6\r\nContienen minerales como el calcio, fósforo, sodio, potasio, hierro, cobre, magnesio, zinc.\r\nTienen propiedades laxantes y diuréticas, favorecen la circulación en las arterias y combaten la arteriosclerosis.\r\nLas vitaminas, como el ácido fólico y la vitamina B6, intervienen en la producción de glóbulos rojos y blancos.','productos/uvas_Wp5i4Pr.png'),(45,'Mamón','Verano','El mamón, también conocido como papaya, es una fruta tropical carnosa y jugosa, de sabor ligeramente dulce, de color verde amarillento que madura a anaranjado. De forma Ovoide, oblonga, periforme o casi cilíndrica, tiene de tamaño 10 a 25 cm o más de largo y de 7 a 15 cm o más de diámetro. Posee numerosas semillas negras, redondas u ovoides y su pulpa es rojiza, muy jugosa, similar a la del melón.\r\nRica en vitamina A y C, potasio, ácido fólico, niacina, tiamina, riboflavina, hierro y fibra.\r\nAyuda a prevenir el estreñimiento, fortalece y reconstruye los huesos, ayuda a prevenir enfermedades cardíacas, ayuda a reducir la inflamación crónica.\r\nPromueve la cicatrización de heridas y previene la infección de quemaduras.\r\nMantiene el cabello hidratado y contribuye al buen funcionamiento del hígado.','productos/papayal_9Xo3jyU.jpg'),(46,'Aceituna','Otoño-Invierno','Es una fruta carnosa con una semilla en su interior, que se obtiene del árbol de olivo (Olea europaea) que puede ser de color verde o negro. Tiene un sabor amargo debido a que contiene oleuropeína, un polifenol. Para quitar el amargor, se somete a un proceso de curado y fermentación. \r\nEs rica en fibra, vitaminas A y E, minerales como sodio y calcio, y grasas saludables.\r\nEstimula la circulación sanguínea, ayuda a reducir la presión arterial, y contribuye a mantener un peso saludable, como sus beneficios mas destacados.','productos/Aceitunas_rTt1q6U.jpg');
