DROP TABLE IF EXISTS `libreria_receta`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `libreria_receta` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `titulo` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `ingredientes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `preparacion` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `tiempo_preparacion` int NOT NULL,
  `dificultad` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `imagen` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `fecha_creacion` datetime(6) NOT NULL,
  `autor_id` int DEFAULT NULL,
  `producto_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `libreria_receta_autor_id_425569bb_fk_auth_user_id` (`autor_id`),
  KEY `libreria_receta_producto_id_be00ed8f_fk_libreria_` (`producto_id`),
  CONSTRAINT `libreria_receta_autor_id_425569bb_fk_auth_user_id` FOREIGN KEY (`autor_id`) REFERENCES `auth_user` (`id`),
  CONSTRAINT `libreria_receta_producto_id_be00ed8f_fk_libreria_` FOREIGN KEY (`producto_id`) REFERENCES `libreria_productotemporada` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
